import { useState } from "react";

export default function App() {
  const [wish, setWish] = useState("");

  return (
    <div
      style={{
        padding: "30px",
        background: "#1e1e2e",
        color: "#cdd6f4",
        minHeight: "100vh",
        fontFamily: "sans-serif",
      }}
    >
      <h2>Список Бажанок 🎁</h2>

      {/* 8. Прив'яжи handleAdd до відправки форми */}
      <form style={{ marginBottom: "20px" }}>
        {/* 9. Зроби цей інпут керованим (додай value та onChange) */}
        <input
          type="text"
          placeholder="Що хочеш купити?"
          style={{
            padding: "10px",
            borderRadius: "5px",
            border: "none",
            marginRight: "10px",
          }}
        />

        <button
          type="submit"
          style={{
            padding: "10px 20px",
            borderRadius: "5px",
            border: "none",
            background: "#a6e3a1",
            cursor: "pointer",
            fontWeight: "bold",
          }}
        >
          Додати
        </button>
      </form>

      <ul style={{ listStyle: "none", padding: 0 }}>
        {/* 10. Пройдися по items через .map() */}
        {/* Для кожного елемента виведи <li>. 
            Всередині <li> виведи текст і кнопку видалення. 
            Не забудь про key! І пам'ятай як правильно передавати аргумент у handleRemove при кліку */}
      </ul>
    </div>
  );
}
